import heapq

def top_k(nums, k):
    """找出数组中最大的 k 个数"""
    min_heap = []
    for num in nums:
        heapq.heappush(min_heap, num)
        if len(min_heap) > k:
            heapq.heappop(min_heap)  # 维持堆大小为 k
    return min_heap  # 堆中保留的就是最大的 k 个

print(top_k([3, 2, 1, 5, 6, 4], 3))  # [4, 5, 6] 或类似
